func NewReader(algorithm string, r io.Reader, options ...Option) (Reader, error) {
	var h hash.Hash
	switch algorithm {
	case AlgorithmSHA1:
		h = sha1.New()
	case AlgorithmSHA256:
		h = sha256.New()
	case AlgorithmSHA512:
		h = sha512.New()
	case AlgorithmMD5:
		h = md5.New()
	default:
		return nil, fmt.Errorf("invalid algorithm: %s", algorithm)
	}

	reader := &reader{
		r:      r,
		hash:   h,
		logger: &logger.SugaredLoggerOnWith{},
	}

	for _, opt := range options {
		opt(reader)
	}

	return reader, nil
}

func MD5FromBytes(bytes []byte) string {
	h := md5.New()
	h.Write(bytes)
	return hex.EncodeToString(h.Sum(nil))
}

func HashFile(path string, algorithm string) (string, error) {
	f, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer f.Close()

	var h hash.Hash
	switch algorithm {
	case AlgorithmCRC32:
		h = crc32.NewIEEE()
	case AlgorithmBlake3:
		h = blake3.New()
	case AlgorithmSHA1:
		h = sha1.New()
	case AlgorithmSHA256:
		h = sha256.New()
	case AlgorithmSHA512:
		h = sha512.New()
	case AlgorithmMD5:
		h = md5.New()
	default:
		return "", fmt.Errorf("unsupport digest method: %s", algorithm)
	}

	r := bufio.NewReader(f)
	_, err = io.Copy(h, r)
	if err != nil {
		return "", err
	}

	return hex.EncodeToString(h.Sum(nil)), nil
}

func MD5FromReader(reader io.Reader) string {
	h := md5.New()
	r := bufio.NewReader(reader)
	if _, err := io.Copy(h, r); err != nil {
		return ""
	}

	return hex.EncodeToString(h.Sum(nil))
}

